#include <vector>
#include <algorithm>
#include <cmath>
#include <utility>
#include <iostream>

// --- Replacement of Macros with Modern C++ Functions ---

/**
 * @brief Calculates the maximum of two values.
 * @tparam T The type of the values.
 * @param a The first value.
 * @param b The second value.
 * @return The larger of a and b.
 */
template <typename T>
constexpr T max_val(T a, T b) {
    return (a > b) ? a : b;
}

/**
 * @brief Calculates the minimum of two values.
 * @tparam T The type of the values.
 * @param a The first value.
 * @param b The second value.
 * @return The smaller of a and b.
 */
template <typename T>
constexpr T min_val(T a, T b) {
    return (a < b) ? a : b;
}

/**
 * @brief Clamps a value x between a lower bound lo and an upper bound hi.
 * @tparam T The type of the value.
 * @param x The value to clamp.
 * @param lo The lower bound.
 * @param hi The upper bound.
 * @return The clamped value.
 */
template <typename T>
constexpr T clamp(T x, T lo, T hi) {
    // Equivalent to MIN(MAX(x, lo), hi)
    return min_val(max_val(x, lo), hi);
}

/**
 * @brief Calculates the absolute value of an integer.
 * @param x The integer value.
 * @return The absolute value.
 */
constexpr int absolute(int x) {
    return (x < 0) ? -x : x;
}

// Note: SWAP and SQR are replaced by std::swap and standard multiplication, respectively.

/**
 * @brief Processes the array by clamping values and then sorting it using Bubble Sort.
 * 
 * @param data The vector of integers to process. Passed by reference to modify in place.
 */
void process(std::vector<int>& data) {
    // 1. Clamping Phase
    // Use a range-based for loop for clean iteration.
    for (int& element : data) {
        // Clamp the element between 0 and 255.
        element = clamp(element, 0, 255);
    }

    // 2. Sorting Phase (Bubble Sort)
    // We use structured control flow (for loops) and std::swap.
    size_t n = data.size();

    // Outer loop controls the number of passes (n-1 passes needed).
    for (size_t i = 0; i < n - 1; ++i) {
        // Inner loop performs comparisons and swaps for the current pass.
        // The last 'i' elements are already in place.
        for (size_t j = 0; j < n - 1 - i; ++j) {
            // Check if adjacent elements are out of order.
            if (data[j] > data[j + 1]) {
                // Use standard library swap function.
                std::swap(data[j], data[j + 1]);
            }
        }
    }
}

