#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>

/**
 * @brief Performs matrix multiplication C = A * B.
 * 
 * Matrices A, B, and C are assumed to be N x N, stored in row-major order
 * in the provided linear memory blocks.
 * 
 * @param matrix_A Pointer to the data block for matrix A (N*N elements).
 * @param matrix_B Pointer to the data block for matrix B (N*N elements).
 * @param matrix_C Pointer to the data block for matrix C (N*N elements, output).
 * @param dimension The dimension N of the N x N matrices.
 */
void matrix_multiply(
    const double* matrix_A, 
    const double* matrix_B, 
    double* matrix_C, 
    size_t dimension) 
{
    // Use size_t for loop counters and dimensions, as it is appropriate for sizes.
    // The original 'register' keyword is obsolete and removed.

    // i iterates over rows of the resulting matrix C (and A).
    for (size_t i = 0; i < dimension; ++i) {
        // j iterates over columns of the resulting matrix C (and B).
        for (size_t j = 0; j < dimension; ++j) {
            double sum = 0.0;

            // k performs the dot product summation: C[i, j] = Sum(A[i, k] * B[k, j])
            for (size_t k = 0; k < dimension; ++k) {
                // Calculate the index for A[i, k]
                // Row i, Column k
                size_t index_a = i * dimension + k;

                // Calculate the index for B[k, j]
                // Row k, Column j
                size_t index_b = k * dimension + j;

                // Accumulate the product
                sum += matrix_A[index_a] * matrix_B[index_b];
            }

            // Store the result C[i, j]
            size_t index_c = i * dimension + j;
            matrix_C[index_c] = sum;
        }
    }
}

