#include <string.h>
#include <stdio.h>

/**
 * Safely copies a string from src to dest, ensuring that dest does not overflow.
 * 
 * @param dest The destination buffer.
 * @param src The source string.
 * @param dest_size The maximum number of bytes that can be written to dest.
 * @return The number of characters copied (excluding the null terminator).
 */
size_t safe_copy_string(char* dest, const char* src, size_t dest_size) {
    if (dest == NULL || src == NULL || dest_size == 0) {
        return 0;
    }

    // Use strncpy to copy at most dest_size - 1 characters
    strncpy(dest, src, dest_size - 1);

    // Manually ensure null termination, as strncpy does not guarantee it
    // if the source string was exactly dest_size - 1 characters long.
    dest[dest_size - 1] = '\0'; 

    // Calculate the actual length copied (excluding the null terminator)
    return strnlen(dest, dest_size);
}

void process(const char* input) {
    // Define the buffer size explicitly
    #define BUFFER_SIZE 16
    char buffer[BUFFER_SIZE];

    // Pass the size of the destination buffer to the safe copy function
    safe_copy_string(buffer, input, BUFFER_SIZE);

    // Example usage: print the safely copied string
    printf("Successfully processed string: %s\n", buffer);
}

